// ========================================
// WF1 v11 - EXTRACT & RATE LIMIT CHECK
// Combines v9 logic + v10 rate limiting
// ========================================

const input = $input.first().json;
const results = input.results || [];

const now = new Date();
const today = now.toISOString().split('T')[0];

console.log('[WF1 v11] ==========================================');
console.log('[WF1 v11] Total clarifications found:', results.length);
console.log('[WF1 v11] Date today:', today);

if (results.length === 0) {
  console.log('[WF1 v11] No clarifications to process');
  return { json: { hasItems: false, items: [], skipped: 0, toProcess: 0 } };
}

const items = [];
let skippedCount = 0;
let rateLimitedCount = 0;

for (const page of results) {
  const props = page.properties;
  const id = page.id;

  // ==========================================
  // EXTRACT BASIC INFO
  // ==========================================
  const title = props['Tiêu đề']?.title?.[0]?.plain_text || 'Untitled';
  const status = props['Tình trạng']?.select?.name || '';
  const nguon = props['Nguồn']?.select?.name || 'CEO';
  const noiDungGoc = props['Nội dung gốc']?.rich_text?.[0]?.plain_text || '';
  const ngayNhan = props['Ngày nhận']?.date?.start || '';
  const ghiChu = props['Ghi chú']?.rich_text?.[0]?.plain_text || '';

  // T2, T3 from Clarification (may be empty)
  const t2NhiemVu = props['T2 - NHIỆM VỤ']?.rich_text?.[0]?.plain_text || '';
  const t3ChiTieu = props['T3 - CHỈ TIÊU']?.rich_text?.[0]?.plain_text || '';

  // ==========================================
  // EMAIL INFO
  // ==========================================
  const emailDauMoi = props['📧 Email đầu mối']?.email || '';

  // HR Relation for email lookup
  const hrRelation = props['👤 Người nhận chỉ đạo (HR)']?.relation || [];
  const hrIds = hrRelation.map(r => r.id);

  // ==========================================
  // OUTCOME RELATION (for T3 lookup)
  // ==========================================
  const outcomeRelation = props['Kết quả mong đợi']?.relation || [];
  const outcomeIds = outcomeRelation.map(r => r.id);

  // ==========================================
  // RATE LIMITING FIELDS
  // ==========================================
  const soLanGui = props['📧 Số lần gửi']?.number || 0;
  const ngayGuiGanNhat = props['📅 Ngày gửi gần nhất']?.date?.start || '';

  console.log('[WF1 v11] Processing:', title.substring(0, 40));
  console.log('  Status:', status);
  console.log('  Outcome IDs:', outcomeIds.length);
  console.log('  HR IDs:', hrIds.length);
  console.log('  Email đầu mối:', emailDauMoi || '(empty)');
  console.log('  Số lần gửi:', soLanGui);
  console.log('  Ngày gửi gần nhất:', ngayGuiGanNhat || '(never)');

  // ==========================================
  // RATE LIMIT CHECK
  // ==========================================
  let shouldSkip = false;
  let skipReason = '';

  // Check: Đã gửi >= 2 lần hôm nay?
  if (ngayGuiGanNhat === today && soLanGui >= 2) {
    shouldSkip = true;
    skipReason = 'Đã gửi ' + soLanGui + ' lần hôm nay (max 2)';
    rateLimitedCount++;
  }

  // Check: Status đã xác nhận thì skip
  if (status === '✅ Đã xác nhận') {
    shouldSkip = true;
    skipReason = 'Đã xác nhận rồi';
  }

  if (shouldSkip) {
    console.log('  ⏭️ SKIPPED:', skipReason);
    skippedCount++;
    continue;
  }

  // ==========================================
  // DETERMINE EMAIL RESOLUTION PATH
  // ==========================================
  let emailPath = 'fallback';
  if (emailDauMoi) {
    emailPath = 'direct';
  } else if (hrIds.length > 0) {
    emailPath = 'hr_lookup';
  }

  // ==========================================
  // ADD TO PROCESS QUEUE
  // ==========================================
  items.push({
    clarificationId: id,
    title,
    status,
    nguon,
    noiDungGoc,
    ngayNhan,
    ghiChu,
    t2NhiemVu,
    t3ChiTieu,

    // Email resolution
    emailDauMoi,
    hrIds,
    emailPath,
    needHrLookup: emailPath === 'hr_lookup',

    // Outcome for T3
    outcomeIds,
    needOutcomeFetch: outcomeIds.length > 0 && !t3ChiTieu,

    // Rate limit tracking
    soLanGuiHienTai: soLanGui,
    ngayGuiGanNhat,
    soLanGuiMoi: ngayGuiGanNhat === today ? soLanGui + 1 : 1,
    isNewToday: ngayGuiGanNhat !== today,

    today,
    pageUrl: page.url
  });

  console.log('  ✅ Added to queue (path:', emailPath, ', needOutcome:', outcomeIds.length > 0 && !t3ChiTieu, ')');
}

console.log('[WF1 v11] ==========================================');
console.log('[WF1 v11] Summary:');
console.log('  Total found:', results.length);
console.log('  Rate limited:', rateLimitedCount);
console.log('  Other skipped:', skippedCount - rateLimitedCount);
console.log('  To process:', items.length);

return {
  json: {
    hasItems: items.length > 0,
    items,
    skipped: skippedCount,
    rateLimited: rateLimitedCount,
    toProcess: items.length,
    timestamp: now.toISOString()
  }
};

// Merge T3 from Outcome
const item = $('🔄 Loop Each Item').first().json;
const outcome = $input.first().json;

let t3FromOutcome = '';

try {
  t3FromOutcome = outcome.properties?.['T3 - CHỈ TIÊU']?.rich_text?.[0]?.plain_text || 
                  outcome.properties?.['Chỉ tiêu thành công']?.rich_text?.[0]?.plain_text || '';
  console.log('[WF1 v11] T3 from Outcome:', t3FromOutcome.substring(0, 50));
} catch (e) {
  console.log('[WF1 v11] Could not extract T3 from Outcome');
}

return {
  json: {
    ...item,
    t3ChiTieu: item.t3ChiTieu || t3FromOutcome,
    t3Source: t3FromOutcome ? 'outcome' : 'clarification'
  }
};

// No Outcome path - pass through
const item = $('🔄 Loop Each Item').first().json;
return { json: { ...item, t3Source: 'clarification' } };

// Extract email from HR record
const item = $('IF: Cần HR Lookup?').first().json;
const hr = $input.first().json;

let hrEmail = '';
let hrName = '';

try {
  hrEmail = hr.properties?.['Email']?.email || 
            hr.properties?.['📧 Email']?.email || '';
  hrName = hr.properties?.['Họ và tên']?.title?.[0]?.plain_text || '';
  console.log('[WF1 v11] HR Email:', hrEmail, 'Name:', hrName);
} catch (e) {
  console.log('[WF1 v11] Could not extract email from HR');
}

return {
  json: {
    ...item,
    hrEmail,
    hrName,
    emailResolved: hrEmail || item.emailDauMoi || 'vynnl@esuhai.com',
    emailSource: hrEmail ? 'hr_lookup' : (item.emailDauMoi ? 'direct' : 'fallback')
  }
};

// Direct/Fallback path - no HR lookup needed
const item = $('IF: Cần HR Lookup?').first().json;

return {
  json: {
    ...item,
    emailResolved: item.emailDauMoi || 'vynnl@esuhai.com',
    emailSource: item.emailDauMoi ? 'direct' : 'fallback'
  }
};

// Build prefill URL for Google Form
const item = $input.first().json;

const baseUrl = 'https://docs.google.com/forms/d/e/1FAIpQLSdzRTOucM4qWwlxyx3yEelDorBv2ADnL8jFUUW7-xpqdidvBw/viewform';
const params = new URLSearchParams();

// Form entry IDs from notion_id_mapping.json
params.append('entry.1684171280', item.clarificationId || '');
params.append('entry.1878008034', item.nguon || '');
params.append('entry.1953342780', item.ngayNhan || '');
params.append('entry.1839616630', item.noiDungGoc || '');
params.append('entry.649583359', item.title?.split(':')[0]?.trim() || '');

// Pre-fill T2, T3 if available
if (item.t2NhiemVu) {
  params.append('entry.1319518938', item.t2NhiemVu);
}
if (item.t3ChiTieu) {
  params.append('entry.1910876946', item.t3ChiTieu);
}

const prefillUrl = baseUrl + '?' + params.toString();

console.log('[WF1 v11] Prefill URL built for:', item.title?.substring(0, 40));
console.log('[WF1 v11] Email to:', item.emailResolved, '(' + item.emailSource + ')');

return {
  json: {
    ...item,
    prefillUrl,
    ccEmail: 'hoangkha@esuhai.com'
  }
};

